1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial quote ---
6	  it.todo("quote with empty item list returns premium 5 G (only processing fee)");
7	
8	  // --- Single item base premiums (with newcomer first-insurance and fee folded in) ---
9	  it.todo("quote for single plain sword (newcomer, 0 years) returns premium 115 G (100 base + 10 first-insurance + 5 fee)");
10	  it.todo("quote for single plain amulet (newcomer) returns premium 71 G (60 base + 6 first-insurance + 5 fee)");
11	  it.todo("quote for single plain staff (newcomer) returns premium 93 G (80 base + 8 first-insurance + 5 fee)");
12	  it.todo("quote for single plain potion (newcomer) returns premium 49 G (40 base + 4 first-insurance + 5 fee)");
13	
14	  // --- Component base premiums (building block of 3) ---
15	  it.todo("quote for 2 runes returns base premium 50 G before policy-wide modifiers (50 + 5 first-insurance + 5 fee = 60 G)");
16	  it.todo("quote for 3 runes applies block: base premium 60 G (60 + 6 first-insurance + 5 fee = 71 G)");
17	  it.todo("quote for 4 runes returns base premium 100 G — no block since block requires exactly 3 (100 + 10 first-insurance + 5 fee = 115 G)");
18	  it.todo("quote for 7 runes returns base premium 175 G (one block of 3 = 60 G + 4 runes × 25 G = 100 G; 175 + 18 first-insurance + 5 fee = 198 G)");
19	
20	  // --- 'Alike' components clarification ---
21	  it.todo("quote for 2 runes + 1 moonstone returns base premium 75 G — no block since types differ (75 + 8 first-insurance + 5 fee = 88 G)");
22	  it.todo("quote for 3 runes + 3 moonstones returns base premium 120 G — two separate blocks (120 + 12 first-insurance + 5 fee = 137 G)");
23	
24	  // --- Item-specific modifier: cursed (applies to that item only) ---
25	  it.todo("quote for cursed sword + plain amulet (newcomer) returns policy base 160 G + 50 G curse on the sword's 100 G base, then first-insurance and fee");
26	
27	  // --- Modifier thresholds ---
28	  it.todo("quote for sword with enchantment exactly 5 applies high-enchantment surcharge (30 % of base premium)");
29	  it.todo("quote for sword with enchantment 4 does NOT apply high-enchantment surcharge");
30	  it.todo("quote for cursed sword with enchantment exactly 5 applies both cursed and high-enchantment surcharges");
31	  it.todo("quote with customer who has exactly 2 years with MHPCO applies the 20 % loyalty discount");
32	
33	  // --- Integration: newcomer with a cursed sword (spec example) ---
34	  it.todo("integration: newcomer (0 years, first contract) cursed sword (steel, enchantment 3) returns premium 165 G");
35	
36	  // --- Integration: long-standing customer's second contract (spec example) ---
37	  it.todo("integration: 3-years customer, 2nd quote in scenario, cursed sword (steel, enchantment 7) returns premium 160 G (loyalty + follow-up + curse + high enchantment + first-insurance per item + fee)");
38	
39	  // --- Rounding in MHPCO's favor ---
40	  it.todo("premium calculation that yields 197.5 G is rounded UP to 198 G");
41	  it.todo("payout calculation that yields 350.5 G is rounded DOWN to 350 G");
42	
43	  // --- Claim: standard reimbursement (no special clauses) ---
44	  it.todo("claim on plain steel sword (enchantment 3) with 500 G damage: payout 400 G (full minus 100 G deductible)");
45	  it.todo("claim on a rune (insurance value 250 G) with 200 G damage: payout 100 G (full minus 100 G deductible; runes have no enchantment/material clauses)");
46	
47	  // --- Claim: high-enchantment clause ---
48	  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");
49	
50	  // --- Claim: dragon-material clause ---
51	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
52	
53	  // --- Claim: both clauses — 50 % rule wins ---
54	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
55	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");
56	
57	  // --- Claim: deductible per damage event (multi-item single incident) ---
58	  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");
59	
60	  // --- Claim: cap = 2 × insurance sum ---
61	  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
62	  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
63	  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");
64	
65	  // --- Claim: cap exhaustion across successive claims ---
66	  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
67	  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");
68	
69	  // --- Claim: multiple items of the same type ---
70	  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
71	  it.todo("claim on two swords (two separate damage entries) treats each entry as separate damage with its own deductible");
72	  it.todo("claim contains more entries of a given type than the policy covers: the whole claim is rejected (error)");
73	
74	  // --- Edge cases / errors ---
75	  it.todo("quote includes an item with unknown type (e.g. broomstick): error, no results");
76	  it.todo("claim references an item not part of the policy (e.g. amulet damage when only a sword is insured): error");
77	  it.todo("claim with a negative damage amount (amount: -200): error");
78	});
